from flask import Flask, redirect, url_for, session, request
from requests_oauthlib import OAuth2Session
import uuid

app = Flask(__name__)
app.secret_key = str(uuid.uuid4())

CLIENT_ID = 'your_client_id'
AUTHORIZATION_BASE_URL = 'https://your_auth_server.com/authorize'
TOKEN_ENDPOINT = 'https://your_auth_server.com/token'

@app.route('/login')
def login():
    oauth = OAuth2Session(CLIENT_ID)
    authorization_url, state = oauth.authorization_url(AUTHORIZATION_BASE_URL)
    session['oauth_state'] = state
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    if 'error' in request.args:
        print('Error:', request.args.get('error'))
        return 'Error occurred'
    oauth = OAuth2Session(CLIENT_ID, state=session.pop('oauth_state', None))
    token_url, _ = oauth.token_endpoint.split('?')
    token_response = oauth.fetch_token(token_url, client_secret='your_client_secret', authorization_response=request.url)
    session['access_token'] = token_response['access_token']
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)